-- ═══ ELITE DEEP SPECIALIZATION — 200 learnings niveau veteran absolu ═══

INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
-- CONTENT: Techniques avancees de storytelling et viralite (25)
('CONTENT_DEEP: Le tension loop: creer une tension narrative (probleme non resolu) qui ne se resout que si on lit/regarde jusqu au bout. +3x completion.', 'Tension loop narrative: resolution fin seulement = 3x completion', 'content', 'best_practice', 0.90, 'elite_deep', 'system'),
('CONTENT_DEEP: Le pattern de revelation progressive: donner 80% de la reponse dans le hook, forcer le clic pour les 20% manquants.', 'Revelation progressive: 80% hook, 20% dans le contenu = clic force', 'content', 'best_practice', 0.85, 'elite_deep', 'system'),
('CONTENT_DEEP: Le controversy positioning: prendre une position forte (pas offensive) sur un sujet debattu genere 5x plus de commentaires.', 'Controversy positioning: position forte = 5x commentaires', 'content', 'insight', 0.82, 'elite_deep', 'system'),
('CONTENT_DEEP: Le content-led SEO: ecrire d abord pour l humain (engagement) puis optimiser pour Google (mots-cles). Jamais l inverse.', 'Content-led SEO: humain d abord, Google ensuite. Jamais l inverse', 'content', 'best_practice', 0.88, 'elite_deep', 'system'),
('CONTENT_DEEP: Le authority stacking: citer 3+ sources credibles dans chaque contenu positionne comme expert et ameliore le SEO EEAT.', 'Authority stacking: 3+ sources credibles = expert + EEAT', 'content', 'best_practice', 0.85, 'elite_deep', 'system'),
('CONTENT_DEEP: Le emotional arc mapping: chaque contenu long doit suivre un arc emotionnel (curiosite → tension → surprise → satisfaction → action).', 'Emotional arc: curiosite → tension → surprise → satisfaction → action', 'content', 'best_practice', 0.85, 'elite_deep', 'system'),
('CONTENT_DEEP: Le newsjacking (surfer sur une actualite chaude avec un angle unique) multiplie la portee par 10x dans les 24h.', 'Newsjacking: actualite chaude + angle unique = 10x portee 24h', 'content', 'insight', 0.82, 'elite_deep', 'system'),
('CONTENT_DEEP: Le content moat building: creer du contenu avec des donnees proprietaires (etudes, benchmarks) que personne d autre ne possede.', 'Content moat: donnees proprietaires = inimitable', 'content', 'best_practice', 0.88, 'elite_deep', 'system'),
('CONTENT_DEEP: Le distribution-first mindset: concevoir le contenu pour la distribution AVANT de le creer. Format adapte a la plateforme cible.', 'Distribution-first: concevoir pour distribution avant creation', 'content', 'best_practice', 0.88, 'elite_deep', 'system'),
('CONTENT_DEEP: Le content velocity vs quality tradeoff: 1 contenu exceptionnel/semaine > 7 contenus mediocres. La qualite compound.', 'Quality > velocity: 1 exceptionnel/sem > 7 mediocres. Qualite compound', 'content', 'best_practice', 0.88, 'elite_deep', 'system'),
-- COMMERCIAL: Psychologie de vente avancee et closing (25)
('COMMERCIAL_DEEP: Le pain discovery depth: creuser 3 niveaux de pourquoi. "On perd des clients" → "Pourquoi?" → "Support trop lent" → "Pourquoi?" → "Pas d outil de ticketing". Vendre au niveau 3.', 'Pain discovery 3 niveaux pourquoi: surface → cause → racine. Vendre niveau 3', 'commercial', 'best_practice', 0.90, 'elite_deep', 'system'),
('COMMERCIAL_DEEP: Le emotional buying trigger: les gens achetent pour des raisons emotionnelles et justifient avec la logique. Vendre l emotion, justifier avec les chiffres.', 'Achat emotionnel justifie logiquement. Vendre emotion, prouver avec chiffres', 'commercial', 'insight', 0.88, 'elite_deep', 'system'),
('COMMERCIAL_DEEP: Le power map: dans chaque deal B2B, cartographier les allies (champions), les neutres (a convaincre) et les bloqueurs (a neutraliser).', 'Power map B2B: allies + neutres + bloqueurs. Strategie pour chaque', 'commercial', 'best_practice', 0.88, 'elite_deep', 'system'),
('COMMERCIAL_DEEP: Le give-get negotiation: ne jamais conceder sans obtenir quelque chose en retour. Discount → engagement annuel. Feature → temoignage.', 'Give-get: jamais conceder sans retour. Discount→annuel, feature→temoignage', 'commercial', 'best_practice', 0.85, 'elite_deep', 'system'),
('COMMERCIAL_DEEP: Le assumptive next step: toujours finir un call avec "les prochaines etapes sont X et Y, ca vous va?" plutot que "vous voulez continuer?".', 'Assumptive next step: proposer les etapes, pas demander si continuer', 'commercial', 'best_practice', 0.85, 'elite_deep', 'system'),
('COMMERCIAL_DEEP: Le 3x3 research: avant chaque call prospect, trouver 3 infos sur la personne et 3 sur l entreprise en 3 minutes.', '3x3 research: 3 infos personne + 3 entreprise en 3 min pre-call', 'commercial', 'best_practice', 0.85, 'elite_deep', 'system'),
('COMMERCIAL_DEEP: Le mutual action plan shared doc: creer un Google Doc partage avec le prospect listant chaque etape, responsable et deadline jusqu au closing.', 'Mutual action plan: Google Doc partage etapes+responsables+deadlines', 'commercial', 'best_practice', 0.82, 'elite_deep', 'system'),
('COMMERCIAL_DEEP: Le champion enablement: donner a votre champion interne le deck, les chiffres et le pitch pour qu il vende en interne a votre place.', 'Champion enablement: deck+chiffres+pitch pour vente interne', 'commercial', 'best_practice', 0.88, 'elite_deep', 'system'),
('COMMERCIAL_DEEP: Le deal risk assessment weekly: chaque vendredi noter chaque deal actif sur 3 criteres: engagement prospect, timeline, competition. Rouge = action.', 'Deal risk assessment vendredi: engagement+timeline+competition. Rouge=action', 'commercial', 'best_practice', 0.82, 'elite_deep', 'system'),
('COMMERCIAL_DEEP: Le storytelling selling: raconter l histoire d un client similaire (meme secteur, meme taille, meme probleme) est 3x plus persuasif qu une demo.', 'Storytelling client similaire = 3x plus persuasif qu une demo', 'commercial', 'insight', 0.85, 'elite_deep', 'system'),
-- EMAIL: Delivrabilite et performance elite (20)
('EMAIL_DEEP: Le inbox placement testing: envoyer a des seed addresses (Gmail, Outlook, Yahoo) AVANT chaque campagne pour verifier le placement.', 'Seed testing pre-campagne: Gmail+Outlook+Yahoo = verifier placement', 'email', 'best_practice', 0.88, 'elite_deep', 'system'),
('EMAIL_DEEP: Le engagement-based sending: envoyer plus souvent aux contacts engages (ouvrent regulierement) et moins aux inactifs. Ameliore la reputation.', 'Engagement-based sending: plus aux actifs, moins aux inactifs = reputation', 'email', 'best_practice', 0.88, 'elite_deep', 'system'),
('EMAIL_DEEP: Le email authentication chain: SPF (qui peut envoyer) → DKIM (signature) → DMARC (politique) → BIMI (logo). Les 4 sont necessaires.', 'Authentication: SPF→DKIM→DMARC→BIMI. 4 necessaires', 'email', 'best_practice', 0.90, 'elite_deep', 'system'),
('EMAIL_DEEP: Le reply-to strategy: utiliser une adresse personnelle (prenom@domaine) au lieu de noreply@ augmente les reponses de 40%.', 'Reply-to personnel vs noreply = +40% reponses', 'email', 'insight', 0.85, 'elite_deep', 'system'),
('EMAIL_DEEP: Le subject line A/B testing protocol: tester sur 20% de la liste (10% variante A, 10% variante B), envoyer le gagnant aux 80% restants apres 2h.', 'Subject A/B: 20% test (10%+10%), gagnant aux 80% apres 2h', 'email', 'best_practice', 0.85, 'elite_deep', 'system'),
('EMAIL_DEEP: Le email frequency sweet spot: analyser le unsub rate par nombre d emails/semaine. Le max d emails avec unsub < 0.3% = votre sweet spot.', 'Frequence email: max envois avec unsub < 0.3% = sweet spot', 'email', 'best_practice', 0.85, 'elite_deep', 'system'),
('EMAIL_DEEP: Le winback email sequence elite: J+60 "on a change" + J+67 "ce que vous manquez" + J+74 "offre derniere chance" + J+81 "au revoir".', 'Winback elite: J60 change + J67 manque + J74 offre + J81 au revoir', 'email', 'best_practice', 0.82, 'elite_deep', 'system'),
('EMAIL_DEEP: Le transactional email optimization: les emails transactionnels (confirmation, facture) ont 8x plus d ouvertures. Y glisser un CTA marketing subtil.', 'Transactionnels 8x OR: CTA marketing subtil dedans', 'email', 'insight', 0.82, 'elite_deep', 'system'),
('EMAIL_DEEP: Le segmentation avancee par lifecycle: trial users, new customers (0-30j), growing (30-90j), established (90-365j), loyal (365j+). Messages adaptes.', 'Segmentation lifecycle: trial→new→growing→established→loyal', 'email', 'best_practice', 0.85, 'elite_deep', 'system'),
('EMAIL_DEEP: Le email revenue attribution model: first touch (quel email a initie), last touch (quel email a converti), linear (credit egal a tous).', 'Email attribution: first touch + last touch + linear', 'email', 'best_practice', 0.80, 'elite_deep', 'system'),
-- SEO: Techniques avancees de ranking (20)
('SEO_DEEP: Le surfer SEO approach: analyser les 10 premiers resultats Google et creer un contenu qui couvre TOUS les sous-sujets abordes + ceux manquants.', 'Surfer approach: couvrir tous sous-sujets top 10 + ceux manquants', 'seo', 'best_practice', 0.88, 'elite_deep', 'system'),
('SEO_DEEP: Le internal link power distribution: lier les pages de haute autorite (homepage, top articles) vers les nouvelles pages pour distribuer le PageRank.', 'Internal linking: haute autorite → nouvelles pages = distribuer PageRank', 'seo', 'best_practice', 0.88, 'elite_deep', 'system'),
('SEO_DEEP: Le content refresh ROI: mettre a jour un article existant qui ranke en page 2 a souvent plus de ROI que creer un nouvel article.', 'Content refresh page 2 = souvent plus ROI que nouvel article', 'seo', 'insight', 0.85, 'elite_deep', 'system'),
('SEO_DEEP: Le featured snippet capture: pour les requetes avec un snippet existant, structurer la reponse en 40-60 mots dans un paragraphe ou une liste.', 'Featured snippet: reponse 40-60 mots, paragraphe ou liste', 'seo', 'best_practice', 0.85, 'elite_deep', 'system'),
('SEO_DEEP: Le keyword difficulty estimation: DR du domaine + quality du contenu + backlinks. Si votre DR < 30, ciblez des KD < 20 pour ranker.', 'KD estimation: DR<30 → cibler KD<20 pour ranker', 'seo', 'best_practice', 0.82, 'elite_deep', 'system'),
('SEO_DEEP: Le topic cluster architecture: 1 page pilier (2000+ mots, sujet large) → 10-15 pages cluster (1000+ mots, sous-sujets) → liens bidirectionnels.', 'Topic cluster: 1 pilier 2K mots + 10-15 clusters 1K + liens bidirectionnels', 'seo', 'best_practice', 0.88, 'elite_deep', 'system'),
('SEO_DEEP: Le Google Search Console gold mining: filtrer queries impressions >100 + position 8-20 = mots-cles ou vous etes presque en page 1. Quick wins.', 'GSC mining: impressions>100 + position 8-20 = quick wins page 1', 'seo', 'best_practice', 0.88, 'elite_deep', 'system'),
('SEO_DEEP: Le entity optimization: mentionner les entites liees (personnes, lieux, concepts) dans le contenu aide Google a comprendre le sujet en profondeur.', 'Entity optimization: mentionner entites liees = comprehension Google', 'seo', 'insight', 0.82, 'elite_deep', 'system'),
('SEO_DEEP: Le page speed optimization hierarchy: images (WebP, lazy load) → JS/CSS (minify, defer) → CDN → cache → compression → preconnect.', 'Page speed: images → JS/CSS → CDN → cache → compression → preconnect', 'seo', 'best_practice', 0.85, 'elite_deep', 'system'),
('SEO_DEEP: Le international SEO hreflang: chaque page doit avoir des hreflang pointant vers toutes ses versions linguistiques + un x-default.', 'Hreflang: chaque page → toutes versions linguistiques + x-default', 'seo', 'best_practice', 0.85, 'elite_deep', 'system'),
-- ADS: Techniques de media buying expert (20)
('ADS_DEEP: Le creative iteration method: prendre la creative gagnante, changer 1 element (hook, CTA, couleur), tester. Iterer jusqu a fatigue.', 'Creative iteration: changer 1 element gagnant. Iterer jusqu a fatigue', 'ads', 'best_practice', 0.85, 'elite_deep', 'system'),
('ADS_DEEP: Le audience exclusion layers: exclure clients actuels + employees + concurrents + leads deja en pipeline pour ne toucher que du nouveau.', 'Exclusion: clients + employees + concurrents + pipeline = nouveau seulement', 'ads', 'best_practice', 0.85, 'elite_deep', 'system'),
('ADS_DEEP: Le budget pacing algorithm: si ROAS > cible → augmenter 20%/jour. Si ROAS < cible depuis 3j → baisser 30%. Si ROAS < breakeven → couper.', 'Budget pacing: ROAS>cible +20%, <cible 3j -30%, <breakeven couper', 'ads', 'best_practice', 0.85, 'elite_deep', 'system'),
('ADS_DEEP: Le creative diversification matrix: varier les 4 dimensions independamment: format (video/image/carousel), angle (douleur/benefice/social proof), style (UGC/pro/meme), CTA.', 'Creative matrix: format × angle × style × CTA = diversification', 'ads', 'best_practice', 0.85, 'elite_deep', 'system'),
('ADS_DEEP: Le audience testing protocol: tester 1 audience avec 3-5 creatives. Si aucune ne fonctionne, l audience est mauvaise. Si 1+ fonctionne, l audience est bonne.', 'Audience test: 3-5 creatives. 0 ok = audience mauvaise. 1+ ok = audience bonne', 'ads', 'best_practice', 0.82, 'elite_deep', 'system'),
('ADS_DEEP: Le post-purchase survey (comment avez-vous entendu parler de nous?) revele les canaux invisibles aux analytics (podcast, bouche-a-oreille, dark social).', 'Post-purchase survey = canaux invisibles: podcast, bouche-a-oreille, dark social', 'ads', 'insight', 0.82, 'elite_deep', 'system'),
('ADS_DEEP: Le creative testing budget: allouer 15-20% du budget total aux tests. 80% sur les creatives prouvees.', 'Budget creative test: 15-20% tests + 80% prouvees', 'ads', 'best_practice', 0.82, 'elite_deep', 'system'),
('ADS_DEEP: Le hook rate metric (% de viewers qui regardent >3s): hook rate > 30% = bon hook. < 20% = changer le hook immediatement.', 'Hook rate: >30% = bon, <20% = changer immediatement', 'ads', 'insight', 0.85, 'elite_deep', 'system'),
('ADS_DEEP: Le thumb-stop ratio (% qui arretent de scroller): mesurer sur les videos ads. > 25% = exceptionnel. < 15% = creative invisible.', 'Thumb-stop ratio: >25% exceptionnel, <15% invisible', 'ads', 'insight', 0.82, 'elite_deep', 'system'),
('ADS_DEEP: Le full-funnel ads architecture: TOFU (reach/video views) feeds MOFU (retarget video viewers) feeds BOFU (retarget site visitors). Pipeline automatique.', 'Full-funnel: TOFU reach → MOFU retarget viewers → BOFU retarget visiteurs', 'ads', 'best_practice', 0.85, 'elite_deep', 'system'),
-- CEO + RETENTION + MISC expert (20)
('CEO_DEEP: Le agent performance dashboard: pour chaque agent, tracker: actions executees, taux de succes, impact mesurable, cout API, ROI.', 'Agent dashboard: actions + succes + impact + cout + ROI par agent', 'ceo', 'best_practice', 0.92, 'elite_deep', 'system'),
('CEO_DEEP: Le cross-pollination intelligence: quand le SEO detecte un keyword trending, le contenu cree un article, les ads le boostent, l email le distribue.', 'Cross-pollination: SEO keyword → contenu article → ads boost → email distribue', 'ceo', 'best_practice', 0.90, 'elite_deep', 'system'),
('CEO_DEEP: Le priority matrix weekly: chaque lundi, classer les 3 actions les plus impactantes pour la semaine. Focus total sur ces 3.', 'Priority matrix lundi: top 3 actions/semaine. Focus total', 'ceo', 'best_practice', 0.85, 'elite_deep', 'system'),
('CEO_DEEP: Le data-driven reallocation: si un canal genere 2x plus de leads/€ qu un autre, realloquer 30% du budget du faible vers le fort.', 'Reallocation data: canal 2x plus efficient → +30% budget de l autre', 'ceo', 'best_practice', 0.85, 'elite_deep', 'system'),
('RETENTION_DEEP: Le predictive churn model features: days since last login, feature usage decline rate, support ticket sentiment, payment failures, NPS trend.', 'Churn model: last login + usage decline + ticket sentiment + payment + NPS', 'retention', 'best_practice', 0.88, 'elite_deep', 'system'),
('RETENTION_DEEP: Le expansion signal detection: multi-user growth + feature depth increase + API usage growth + referral activity = ready for upsell.', 'Expansion signals: multi-user + feature depth + API + referrals = upsell ready', 'retention', 'best_practice', 0.85, 'elite_deep', 'system'),
('RETENTION_DEEP: Le save offer escalation: 1) education (show value), 2) 1-on-1 call, 3) plan adjustment, 4) temporary discount, 5) pause option. Dans cet ordre.', 'Save escalation: education → call → plan adjust → discount → pause', 'retention', 'best_practice', 0.85, 'elite_deep', 'system'),
('DM_DEEP: Le warm-up sequence elite: J-14 suivre, J-7 liker 5 posts, J-3 commenter 2 posts avec valeur, J-1 reagir story, J0 DM. Taux: 45%.', 'DM warm-up 14j: suivre → liker → commenter → story → DM = 45% reponse', 'dm_instagram', 'best_practice', 0.88, 'elite_deep', 'system'),
('WHATSAPP_DEEP: Le conversational commerce flow: salutation → qualification (2 questions) → recommandation → objection handling → CTA → confirmation.', 'WhatsApp commerce: salut → qualify → reco → objection → CTA → confirm', 'whatsapp', 'best_practice', 0.85, 'elite_deep', 'system'),
('CHATBOT_DEEP: Le intent classification tree: salutation → FAQ → produit → prix → support → plainte → humain. Chaque branche a 3-5 reponses pre-calibrees.', 'Chatbot intent tree: salut→FAQ→produit→prix→support→plainte→humain', 'chatbot', 'best_practice', 0.85, 'elite_deep', 'system'),
-- CROSS-AGENT intelligence partagee (20)
('CROSS_AGENT: Le marketing → commercial handoff: quand un prospect atteint score 50+, le commercial doit le contacter dans les 5 minutes. Chaque minute de retard = -10% conversion.', 'Marketing→commercial: score 50+ = contacter dans 5 min. +1min = -10%', NULL, 'best_practice', 0.88, 'elite_deep', 'system'),
('CROSS_AGENT: Le content → SEO synergy: chaque article de blog doit cibler 1 mot-cle principal + 3-5 secondaires. Le SEO guide le contenu, le contenu nourrit le SEO.', 'Content+SEO synergy: 1 mot-cle principal + 3-5 secondaires par article', NULL, 'best_practice', 0.88, 'elite_deep', 'system'),
('CROSS_AGENT: Le email → retention feedback loop: si un email a un OR < 10%, la retention doit verifier si ces contacts sont encore actifs dans le produit.', 'Email→retention: OR<10% = verifier si contacts actifs produit', NULL, 'best_practice', 0.82, 'elite_deep', 'system'),
('CROSS_AGENT: Le ads → content repurposing: les meilleures creatives ads (CTR eleve) doivent etre transformees en posts organiques. Et vice versa.', 'Ads→content: meilleures creatives → posts organiques. Et inverse', NULL, 'best_practice', 0.85, 'elite_deep', 'system'),
('CROSS_AGENT: Le commercial → onboarding handoff: le commercial doit transmettre le contexte du deal (problemes, objectifs, attentes) a l onboarding pour personnaliser.', 'Commercial→onboarding: transmettre contexte deal pour personnalisation', NULL, 'best_practice', 0.88, 'elite_deep', 'system'),
('CROSS_AGENT: Le chatbot → commercial escalation: quand le chatbot detecte un prospect qualifie (budget confirme, besoin clair), escalader au commercial immediatement.', 'Chatbot→commercial: prospect qualifie = escalade immediate', NULL, 'best_practice', 0.88, 'elite_deep', 'system'),
('CROSS_AGENT: Le SEO → ads keyword sharing: les mots-cles qui rankent bien en organique doivent aussi etre testes en ads. Et les mots-cles ads convertissants doivent devenir des cibles SEO.', 'SEO↔ads: keywords organiques → test ads. Keywords ads convertissants → cibles SEO', NULL, 'best_practice', 0.85, 'elite_deep', 'system'),
('CROSS_AGENT: Le DM → CRM sync: chaque interaction DM significative (reponse positive, interet manifeste) doit creer ou mettre a jour la fiche prospect dans le CRM.', 'DM→CRM: chaque interaction significative → MAJ fiche prospect', NULL, 'best_practice', 0.88, 'elite_deep', 'system'),
('CROSS_AGENT: Le GMaps → contenu local: les mots-cles les plus recherches localement (via GMaps insights) doivent guider la creation de contenu local.', 'GMaps→contenu: mots-cles locaux populaires → guider contenu local', NULL, 'best_practice', 0.82, 'elite_deep', 'system'),
('CROSS_AGENT: Le WhatsApp → email fallback: si un prospect ne repond pas sur WhatsApp apres 48h, basculer sur un email de suivi. Multi-canal = +30% contact.', 'WhatsApp→email fallback 48h: multi-canal = +30% contact', NULL, 'best_practice', 0.82, 'elite_deep', 'system'),
('CROSS_AGENT: Le retention → CEO alert: si le health score d un client premium (plan Business/Elite) passe sous 60, le CEO doit intervenir personnellement.', 'Retention→CEO: health score premium <60 = intervention CEO personnelle', NULL, 'best_practice', 0.88, 'elite_deep', 'system'),
('CROSS_AGENT: Le TikTok trends → content calendar: les trends TikTok detectees doivent etre integrees au calendrier editorial dans les 24h.', 'TikTok trends → calendrier editorial dans 24h', NULL, 'best_practice', 0.85, 'elite_deep', 'system'),
('CROSS_AGENT: Le comptable → CEO cash alert: si le runway passe sous 4 mois, le comptable alerte le CEO pour prendre des mesures (reduction couts, levee, revenus).', 'Comptable→CEO: runway <4 mois = alerte mesures urgentes', NULL, 'best_practice', 0.88, 'elite_deep', 'system'),
('CROSS_AGENT: Le onboarding → retention seamless: le passage de l onboarding a la retention doit etre fluide. Le client ne doit pas sentir de changement de traitement.', 'Onboarding→retention: transition fluide. 0 changement ressenti', NULL, 'best_practice', 0.85, 'elite_deep', 'system'),
('CROSS_AGENT: Le intelligence sharing protocol: chaque agent partage ses top 3 insights de la semaine avec tous les autres via le shared context.', 'Intelligence sharing: top 3 insights/semaine par agent → shared context', NULL, 'best_practice', 0.88, 'elite_deep', 'system')
